import { foo } from './foo';
const bar = require('bar');

const CONST = 99;

export function processData(items) {
    const results = [];
    for (const item of items) {
        if (!item) {
            continue;
        }
        const clean = item.trim().toLowerCase();
        results.push(clean);
    }
    return results;
}

class Widget {
    constructor(name) {
        this.name = name;
        this.count = 0;
    }

    render(ctx) {
        ctx.clear();
        ctx.draw(this.name);
        this.count += 1;
        return ctx;
    }
}

module.exports = { processData, Widget };

